const FALLBACK = 'en'

/** Return a translator bound to `lang`, falling back to English. */
export function makeT(lang) {
  return (key) => {
    const entry = STRINGS[key]
    if (!entry) return key
    return entry[lang] ?? entry[FALLBACK] ?? key
  }
}

/** Best-effort match of the browser language to an offered language code. */
export function detectLang() {
  const codes = LANGS.map((l) => l.code)
  const nav = (typeof navigator !== 'undefined' && navigator.language) || ''
  const base = nav.toLowerCase().split('-')[0]
  return codes.includes(base) ? base : FALLBACK
}
